/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Each audit entry captures the channel used, recipient, priority, subject,
 * and timestamp so that notification history can be queried and reviewed.
 */

import type { NotificationPriority } from './priority-router.js';

export interface AuditEntry {
  id: string;
  channel: 'sms' | 'email' | 'webhook';
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  timestamp: Date;
  overridden: boolean;
}

let nextId = 1;

function generateAuditId(): string {
  return `audit-${String(nextId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  record(params: {
    channel: 'sms' | 'email' | 'webhook';
    priority: NotificationPriority;
    recipient: string;
    subject: string;
    overridden?: boolean;
  }): AuditEntry {
    const entry: AuditEntry = {
      id: generateAuditId(),
      channel: params.channel,
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      timestamp: new Date(),
      overridden: params.overridden ?? false,
    };
    this.entries.push(entry);
    return entry;
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: 'sms' | 'email' | 'webhook'): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — stores per-user channel preferences
 * that override the default priority-based routing.
 *
 * When a user has a channel preference set, the PriorityRouter will use
 * that channel instead of the one determined by notification priority.
 */

export type NotificationChannel = 'sms' | 'email' | 'webhook';

export interface UserPreference {
  userId: string;
  channel: NotificationChannel;
}

export class NotificationPreferencesService {
  private preferences: Map<string, NotificationChannel> = new Map();

  setPreference(userId: string, channel: NotificationChannel): void {
    this.preferences.set(userId, channel);
  }

  getPreference(userId: string): NotificationChannel | undefined {
    return this.preferences.get(userId);
  }

  removePreference(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  hasPreference(userId: string): boolean {
    return this.preferences.has(userId);
  }

  getAllPreferences(): UserPreference[] {
    return Array.from(this.preferences.entries()).map(([userId, channel]) => ({
      userId,
      channel,
    }));
  }

  clear(): void {
    this.preferences.clear();
  }
}

