export class PriorityRouter {
  private logger = new Logger('PriorityRouter');
  private routeLog: RouteResult[] = [];
  private auditService?: AuditService;
  private preferencesService?: NotificationPreferencesService;

  constructor(
    private emailService: NotificationService,
    private smsService: SmsNotificationService,
    private webhookService: WebhookNotificationService,
  ) {}

  setAuditService(auditService: AuditService): void {
    this.auditService = auditService;
  }

  setPreferencesService(preferencesService: NotificationPreferencesService): void {
    this.preferencesService = preferencesService;
  }

  route(notification: PriorityNotification): RouteResult {
    const result = this.resolveRoute(notification);
    this.routeLog.push(result);
    this.auditService?.record({
      channel: result.channel,
      priority: notification.priority,
      recipient: notification.recipient,
      subject: notification.subject,
      overridden: result.overridden,
    });
    return result;
  }

  private resolveRoute(notification: PriorityNotification): RouteResult {
    const preferredChannel = this.preferencesService?.getPreference(notification.recipient);

    if (preferredChannel) {
      this.logger.info(
        `User preference override: routing ${notification.priority} notification to ${preferredChannel} for ${notification.recipient}`,
      );
      return this.routeToChannel(preferredChannel, notification, true);
    }

    switch (notification.priority) {
      case 'urgent':
        return this.routeToSms(notification);
      case 'normal':
        return this.routeToEmail(notification);
      case 'low':
        return this.routeToWebhook(notification);
    }
  }

  private routeToChannel(
    channel: 'sms' | 'email' | 'webhook',
    notification: PriorityNotification,
    overridden: boolean,
  ): RouteResult {
    switch (channel) {
      case 'sms':
        return this.routeToSms(notification, overridden);
      case 'email':
        return this.routeToEmail(notification, overridden);
      case 'webhook':
        return this.routeToWebhook(notification, overridden);
    }
  }

