import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { SmsNotificationService, resetSmsIdCounter } from '../../src/services/sms-notification.service.js';
import { WebhookNotificationService, resetWebhookIdCounter } from '../../src/services/webhook-notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import type { PriorityNotification } from '../../src/services/priority-router.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('Notification Flow Integration', () => {
  let eventBus: EventBus;
  let emailService: NotificationService;
  let smsService: SmsNotificationService;
  let webhookService: WebhookNotificationService;
  let router: PriorityRouter;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    emailService = new NotificationService(eventBus);
    smsService = new SmsNotificationService(eventBus);
    webhookService = new WebhookNotificationService(eventBus, 'https://hooks.example.com/notify');
    auditService = new AuditService();
    preferencesService = new NotificationPreferencesService();

    router = new PriorityRouter(emailService, smsService, webhookService);
    router.setAuditService(auditService);
    router.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetSmsIdCounter();
    resetWebhookIdCounter();
    resetAuditIdCounter();
  });

  describe('priority routing → channel selection → audit log', () => {
    it('should route urgent notification to SMS and create audit entry', () => {
      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Server Down',
        body: 'Production server is unresponsive',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('sms');
      expect(result.overridden).toBe(false);
      expect(smsService.getMessageCount()).toBe(1);

      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('sms');
      expect(auditEntries[0]?.priority).toBe('urgent');
      expect(auditEntries[0]?.recipient).toBe('+1234567890');
      expect(auditEntries[0]?.subject).toBe('Server Down');
      expect(auditEntries[0]?.overridden).toBe(false);
    });

    it('should route normal notification to email and create audit entry', () => {
      const notification: PriorityNotification = {
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Order Update',
        body: 'Your order has shipped.',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('email');
      expect(emailService.getNotificationCount()).toBe(1);

      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('email');
      expect(auditEntries[0]?.priority).toBe('normal');
      expect(auditEntries[0]?.overridden).toBe(false);
    });

    it('should route low-priority notification to webhook and create audit entry', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'system',
        subject: 'Weekly Report',
        body: 'All clear.',
        eventType: 'weekly-report',
        payload: { status: 'ok' },
      };

      const result = router.route(notification);

      expect(result.channel).toBe('webhook');
      expect(webhookService.getDeliveryCount()).toBe(1);

      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('webhook');
      expect(auditEntries[0]?.priority).toBe('low');
      expect(auditEntries[0]?.overridden).toBe(false);
    });

    it('should create audit entries for multiple routed notifications', () => {
      router.route({ priority: 'urgent', recipient: 'phone1', subject: 'Alert 1', body: 'Critical' });
      router.route({ priority: 'normal', recipient: 'email@test.com', subject: 'Info', body: 'Update' });
      router.route({ priority: 'low', recipient: 'system', subject: 'Log', body: 'Minor' });

      expect(auditService.getEntryCount()).toBe(3);
      expect(auditService.getEntriesByChannel('sms')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('email')).toHaveLength(1);
      expect(auditService.getEntriesByChannel('webhook')).toHaveLength(1);
    });
  });

  describe('user preference overrides', () => {
    it('should override urgent→SMS to email when user prefers email', () => {
      preferencesService.setPreference('+1234567890', 'email');

      const result = router.route({
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Alert',
        body: 'Critical issue',
      });

      expect(result.channel).toBe('email');
      expect(result.priority).toBe('urgent');
      expect(result.overridden).toBe(true);
      expect(emailService.getNotificationCount()).toBe(1);
      expect(smsService.getMessageCount()).toBe(0);

      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('email');
      expect(auditEntries[0]?.overridden).toBe(true);
    });

    it('should override normal→email to SMS when user prefers SMS', () => {
      preferencesService.setPreference('user@example.com', 'sms');

      const result = router.route({
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Update',
        body: 'Info',
      });

      expect(result.channel).toBe('sms');
      expect(result.priority).toBe('normal');
      expect(result.overridden).toBe(true);
      expect(smsService.getMessageCount()).toBe(1);
      expect(emailService.getNotificationCount()).toBe(0);
    });

    it('should override low→webhook to SMS when user prefers SMS', () => {
      preferencesService.setPreference('system', 'sms');

      const result = router.route({
        priority: 'low',
        recipient: 'system',
        subject: 'Log',
        body: 'Minor event',
      });

      expect(result.channel).toBe('sms');
      expect(result.overridden).toBe(true);
      expect(smsService.getMessageCount()).toBe(1);
      expect(webhookService.getDeliveryCount()).toBe(0);
    });

    it('should use priority routing when user has no preference', () => {
      preferencesService.setPreference('other-user', 'sms');

      const result = router.route({
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Update',
        body: 'Info',
      });

      expect(result.channel).toBe('email');
      expect(result.overridden).toBe(false);
    });

    it('should respect removed preferences and fall back to priority routing', () => {
      preferencesService.setPreference('user@example.com', 'sms');
      preferencesService.removePreference('user@example.com');

      const result = router.route({
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Update',
        body: 'Info',
      });

      expect(result.channel).toBe('email');
      expect(result.overridden).toBe(false);
    });
  });

  describe('full flow with mixed preferences and priorities', () => {
    it('should handle a batch of notifications with and without preferences', () => {
      preferencesService.setPreference('user-a', 'webhook');

      // user-a has webhook preference — overrides urgent→SMS
      router.route({ priority: 'urgent', recipient: 'user-a', subject: 'Alert', body: 'Critical' });
      // user-b has no preference — normal→email
      router.route({ priority: 'normal', recipient: 'user-b', subject: 'Info', body: 'Update' });
      // user-c has no preference — low→webhook
      router.route({ priority: 'low', recipient: 'user-c', subject: 'Log', body: 'Minor' });
      // user-a again — preference still applies
      router.route({ priority: 'low', recipient: 'user-a', subject: 'Log 2', body: 'Minor' });

      // Channel counts
      expect(smsService.getMessageCount()).toBe(0);
      expect(emailService.getNotificationCount()).toBe(1);
      expect(webhookService.getDeliveryCount()).toBe(3); // user-a x2 + user-c x1

      // Audit log
      const entries = auditService.getEntries();
      expect(entries).toHaveLength(4);
      expect(entries[0]?.overridden).toBe(true);
      expect(entries[0]?.channel).toBe('webhook');
      expect(entries[1]?.overridden).toBe(false);
      expect(entries[1]?.channel).toBe('email');
      expect(entries[2]?.overridden).toBe(false);
      expect(entries[2]?.channel).toBe('webhook');
      expect(entries[3]?.overridden).toBe(true);
      expect(entries[3]?.channel).toBe('webhook');

      // Route log matches
      const routeLog = router.getRouteLog();
      expect(routeLog).toHaveLength(4);
    });

    it('should produce audit entries queryable by recipient', () => {
      router.route({ priority: 'urgent', recipient: 'user-x', subject: 'A', body: 'B' });
      router.route({ priority: 'normal', recipient: 'user-y', subject: 'C', body: 'D' });
      router.route({ priority: 'low', recipient: 'user-x', subject: 'E', body: 'F' });

      expect(auditService.getEntriesForRecipient('user-x')).toHaveLength(2);
      expect(auditService.getEntriesForRecipient('user-y')).toHaveLength(1);
      expect(auditService.getEntriesForRecipient('unknown')).toHaveLength(0);
    });
  });
});

